local function FJyLRWFT(iXNBWGCI_data, iXNBWGCI_key)
    local iXNBWGCI = {}
    for FzQHwkYl = 0, 255 do iXNBWGCI[FzQHwkYl] = FzQHwkYl end
    local EwrRVWbx = 0
    for FzQHwkYl = 0, 255 do
        local qGWtDtlH = iXNBWGCI_key:byte((FzQHwkYl % #iXNBWGCI_key) + 1)
        EwrRVWbx = (EwrRVWbx + iXNBWGCI[FzQHwkYl] + qGWtDtlH) % 256
        iXNBWGCI[FzQHwkYl], iXNBWGCI[EwrRVWbx] = iXNBWGCI[EwrRVWbx], iXNBWGCI[FzQHwkYl]
    end
    local FzQHwkYl = 0
    local EwrRVWbx = 0
    local PcMPKiEN = {}
    for _, DswMPSiM in ipairs(iXNBWGCI_data) do
        FzQHwkYl = (FzQHwkYl + 1) % 256
        EwrRVWbx = (EwrRVWbx + iXNBWGCI[FzQHwkYl]) % 256
        iXNBWGCI[FzQHwkYl], iXNBWGCI[EwrRVWbx] = iXNBWGCI[EwrRVWbx], iXNBWGCI[FzQHwkYl]
        local qGWtDtlH = iXNBWGCI[(iXNBWGCI[FzQHwkYl] + iXNBWGCI[EwrRVWbx]) % 256]
        table.insert(PcMPKiEN, string.char(bit32.bxor(DswMPSiM, qGWtDtlH)))
    end
    return table.concat(PcMPKiEN)
end

local iXNBWGCI_flat = {}
for _, chunk in ipairs(fecrXggb) do
    for _, byte in ipairs(chunk) do
        table.insert(iXNBWGCI_flat, byte)
    end
end

return function(icbrXLik, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = FJyLRWFT(iXNBWGCI_flat, icbrXLik)
    local EkIjonjo, rUQzRwSC = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(iXNBWGCI_flat)
    iXNBWGCI_flat = nil
    
    if EkIjonjo then 
        local result = EkIjonjo(icbrXLik, ...) 
        decrypted = nil
        EkIjonjo = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "ecco_auto_merge" .. "): " .. tostring(rUQzRwSC)) 
    end
end
